package scanner

import (
	"context"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/navidrome/navidrome/conf"
	"github.com/navidrome/navidrome/db"
	"github.com/navidrome/navidrome/log"
	"github.com/navidrome/navidrome/model"
	"github.com/navidrome/navidrome/tests"
	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"
)

func TestScannerIntegration(t *testing.T) {
	tests.Init(t, true)
	conf.Server.DbPath = "file::memory:?cache=shared"
	defer db.Init()()
	log.SetLevel(log.LevelFatal)
	RegisterFailHandler(Fail)
	RunSpecs(t, "Scanner Integration Suite")
}

var _ = Describe("Scanner Integration Tests", func() {
	var (
		ctx       context.Context
		ds        model.DataStore
		scanner   FolderScanner
		tempDir   string
		library   model.Library
	)

	BeforeEach(func() {
		ctx = context.Background()
		ds = db.DefaultDataStore()
		scanner = NewTagScanner(ds, nil, nil)

		// Create a temporary directory for test fixtures
		var err error
		tempDir, err = os.MkdirTemp("", "scanner-test-*")
		Expect(err).NotTo(HaveOccurred())

		// Create a test library
		library = model.Library{
			ID:         1,
			Name:       "Test Library",
			Path:       tempDir,
			LastScanAt: time.Time{},
		}

		// Store the library in DB
		libRepo := ds.Library(ctx)
		err = libRepo.Put(&library)
		Expect(err).NotTo(HaveOccurred())
	})

	AfterEach(func() {
		// Clean up temporary directory
		if tempDir != "" {
			os.RemoveAll(tempDir)
		}
	})

	Describe("Full scan with test fixture audio files", func() {
		It("should import all tracks from fixture directory", func() {
			// Copy test fixture files to temp directory
			err := copyTestFixtures(tempDir)
			Expect(err).NotTo(HaveOccurred())

			// Run full scan
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, library, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeNumerically(">", 0))

			// Verify tracks were imported
			mediaFileRepo := ds.MediaFile(ctx)
			allFiles, err := mediaFileRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).NotTo(BeEmpty())

			// Verify at least one track has expected metadata
			testMp3 := findMediaFileByName(allFiles, "test.mp3")
			Expect(testMp3).NotTo(BeNil())
			Expect(testMp3.Path).To(ContainSubstring("test.mp3"))
			Expect(testMp3.LibraryID).To(Equal(library.ID))
		})

		It("should extract metadata for tracks", func() {
			// Copy test fixture files
			err := copyTestFixtures(tempDir)
			Expect(err).NotTo(HaveOccurred())

			// Run full scan
			progress := make(chan uint32, 100)
			_, err = scanner.Scan(ctx, library, true, progress)
			Expect(err).NotTo(HaveOccurred())

			// Verify metadata extraction
			mediaFileRepo := ds.MediaFile(ctx)
			allFiles, err := mediaFileRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())

			// Check that files have core metadata fields populated
			for _, mf := range allFiles {
				// All imported files should have at least a path
				Expect(mf.Path).NotTo(BeEmpty())
				// They should have a suffix/extension
				Expect(mf.Suffix).NotTo(BeEmpty())
				// They should have been assigned an ID
				Expect(mf.ID).NotTo(BeEmpty())
			}
		})

		It("should create album records from track metadata", func() {
			// Copy test fixture files
			err := copyTestFixtures(tempDir)
			Expect(err).NotTo(HaveOccurred())

			// Run full scan
			progress := make(chan uint32, 100)
			_, err = scanner.Scan(ctx, library, true, progress)
			Expect(err).NotTo(HaveOccurred())

			// Verify albums were created
			albumRepo := ds.Album(ctx)
			albums, err := albumRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(albums).NotTo(BeEmpty())

			// Verify albums have expected attributes
			for _, album := range albums {
				Expect(album.ID).NotTo(BeEmpty())
				Expect(album.LibraryID).To(Equal(library.ID))
			}
		})

		It("should create artist records from track metadata", func() {
			// Copy test fixture files
			err := copyTestFixtures(tempDir)
			Expect(err).NotTo(HaveOccurred())

			// Run full scan
			progress := make(chan uint32, 100)
			_, err = scanner.Scan(ctx, library, true, progress)
			Expect(err).NotTo(HaveOccurred())

			// Verify artists were created
			artistRepo := ds.Artist(ctx)
			artists, err := artistRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(artists).NotTo(BeEmpty())

			// Verify artists have expected attributes
			for _, artist := range artists {
				Expect(artist.ID).NotTo(BeEmpty())
				Expect(artist.LibraryID).To(Equal(library.ID))
			}
		})
	})

	Describe("Incremental scan with no changes", func() {
		It("should detect no changes when files are unchanged", func() {
			// Initial full scan
			err := copyTestFixtures(tempDir)
			Expect(err).NotTo(HaveOccurred())

			progress := make(chan uint32, 100)
			initialChangeCount, err := scanner.Scan(ctx, library, true, progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(initialChangeCount).To(BeNumerically(">", 0))

			// Update library's LastScanAt to prevent re-import
			library.LastScanAt = time.Now().Add(-1 * time.Hour)
			libRepo := ds.Library(ctx)
			err = libRepo.UpdateLastScan(library.ID, library.LastScanAt)
			Expect(err).NotTo(HaveOccurred())

			// Run incremental scan with no file changes
			progress = make(chan uint32, 100)
			incrementalChangeCount, err := scanner.Scan(ctx, library, false, progress)
			Expect(err).NotTo(HaveOccurred())

			// Second scan should detect no changes since files haven't been modified
			Expect(incrementalChangeCount).To(Equal(int64(0)))
		})

		It("should not duplicate track records on re-scan", func() {
			// Initial scan
			err := copyTestFixtures(tempDir)
			Expect(err).NotTo(HaveOccurred())

			progress := make(chan uint32, 100)
			_, err = scanner.Scan(ctx, library, true, progress)
			Expect(err).NotTo(HaveOccurred())

			mediaFileRepo := ds.MediaFile(ctx)
			initialFiles, err := mediaFileRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			initialCount := len(initialFiles)

			// Update library LastScanAt
			library.LastScanAt = time.Now().Add(-1 * time.Hour)
			libRepo := ds.Library(ctx)
			err = libRepo.UpdateLastScan(library.ID, library.LastScanAt)
			Expect(err).NotTo(HaveOccurred())

			// Re-scan with full flag
			progress = make(chan uint32, 100)
			_, err = scanner.Scan(ctx, library, true, progress)
			Expect(err).NotTo(HaveOccurred())

			// Count should remain the same (no duplicates)
			allFiles, err := mediaFileRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(len(allFiles)).To(Equal(initialCount))
		})
	})

	Describe("File deletion detection", func() {
		It("should remove tracks when source files are deleted", func() {
			// Initial scan with fixture files
			err := copyTestFixtures(tempDir)
			Expect(err).NotTo(HaveOccurred())

			progress := make(chan uint32, 100)
			_, err = scanner.Scan(ctx, library, true, progress)
			Expect(err).NotTo(HaveOccurred())

			mediaFileRepo := ds.MediaFile(ctx)
			initialFiles, err := mediaFileRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(initialFiles).NotTo(BeEmpty())
			initialCount := len(initialFiles)

			// Delete all audio files from the directory
			files, err := os.ReadDir(tempDir)
			Expect(err).NotTo(HaveOccurred())
			for _, file := range files {
				if !file.IsDir() && model.IsAudioFile(filepath.Join(tempDir, file.Name())) {
					err = os.Remove(filepath.Join(tempDir, file.Name()))
					Expect(err).NotTo(HaveOccurred())
				}
			}

			// Update library LastScanAt to force re-scan
			library.LastScanAt = time.Now().Add(-2 * time.Hour)
			libRepo := ds.Library(ctx)
			err = libRepo.UpdateLastScan(library.ID, library.LastScanAt)
			Expect(err).NotTo(HaveOccurred())

			// Run scan again
			progress = make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, library, false, progress)
			Expect(err).NotTo(HaveOccurred())

			// Should detect deletions
			Expect(changeCount).To(BeNumerically(">", 0))

			// Files should be removed from DB
			remainingFiles, err := mediaFileRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(len(remainingFiles)).To(BeLessThan(initialCount))
		})

		It("should handle empty directory gracefully", func() {
			// Create empty directory
			subdir := filepath.Join(tempDir, "empty")
			err := os.MkdirAll(subdir, 0755)
			Expect(err).NotTo(HaveOccurred())

			// Scan empty directory
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, library, true, progress)

			// Should handle gracefully (no error or zero changes expected)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(0)))

			// No tracks should be imported
			mediaFileRepo := ds.MediaFile(ctx)
			files, err := mediaFileRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(files).To(BeEmpty())
		})
	})

	Describe("Error handling for corrupted files", func() {
		It("should skip corrupted audio files and continue scanning", func() {
			// Copy valid test fixtures
			err := copyTestFixtures(tempDir)
